qry:select.qry:xquery:
		for $r in SQL('

	{%?(#SOURCE:@START='')
		{% %}
		{% fromrow {%=#SOURCE:@START%} %}
	%}
	{%?(#SOURCE:@LEN='')
		{% %}
		{% maxsize {%=#SOURCE:@LEN%} %}
	%}

	SELECT 
	  SEC.policy as policy,
	  TTA22_LICENCIAS_ROL.oi_licencia_rol as ID, 
	  PER16_LICENCIAS.c_licencia as COD, 
	  TTA22_LICENCIAS_ROL.d_licencia_rol as DES

	FROM
		NMD_SECURITY(class=\'NucleusRH.Base.Tiempos_Trabajados.LicenciasRol.LICENCIA_ROL\') as SEC,
	  TTA22_LICENCIAS_ROL,
	  PER16_LICENCIAS

	JOIN
		TTA22_LICENCIAS_ROL.oi_licencia_rol LEFT OUTER SEC.id,
		TTA22_LICENCIAS_ROL.oi_licencia INNER PER16_LICENCIAS.oi_licencia

	WHERE
		1=1
		{%?(#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %}
		{%?(#SOURCE:@TXT_FIND='') {% %} {% and (contain(ucase(DES),{upper-case(#SOURCE:@TXT_FIND)}) or contain(ucase(COD),{upper-case(#SOURCE:@TXT_FIND)})) %} %}
		{%?(#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE%} %} %}
		and TTA22_LICENCIAS_ROL.l_habilitar = 1

	{%?(#SOURCE:@ORDERBY='')
		{% order by COD asc %}
		{% order by {%=#SOURCE:@ORDERBY%} asc %}
	%}				  

')/ROWS/ROW

		for $r in SQL('

	{%?(#FILTER:@LEN='')
		{% %}
		{% maxsize {%=#FILTER:@LEN%} %}
	%}

	SELECT 
	  TTA22_LICENCIAS_ROL.oi_licencia_rol as ID				  
		{%?($FILTER/@order!='')
			{% ,TTA22_LICENCIAS_ROL.{%=$FILTER/@order%} as COL_ORDER %}
			{% %}
		%}

	FROM 
	  TTA22_LICENCIAS_ROL
	  {%?($FILTER/@search!='')
			{% ,PER16_LICENCIAS %}
			{% %}
		%}

	{%?($FILTER/@search!='')
		{% JOIN
			   TTA22_LICENCIAS_ROL.oi_licencia INNER PER16_LICENCIAS.oi_licencia %}
		{% %}
	%}

	WHERE
		1=1			
		{%?($FILTER/@search!='')
			{% and (contain(ucase(TTA22_LICENCIAS_ROL.d_licencia_rol),{upper-case($FILTER/@search)})
		 		 or contain(ucase(PER16_LICENCIAS.d_licencia),{upper-case($FILTER/@search)})
		 		 or contain(ucase(PER16_LICENCIAS.c_licencia),{upper-case($FILTER/@search)})) %}
			{% %}
		%}
		{%?($FILTER/@d_rol!='')
			{% and TTA22_LICENCIAS_ROL.d_rol = {$FILTER/@d_rol} %}
			{% %}
		%}

	{%?($FILTER/@order!='')
	  {% order by COL_ORDER {%=iif($FILTER/@asc='1','asc','desc')%} %}
	  {% %}
	%}

')/ROWS/ROW

		for $r in SQL('

	{%?(#SOURCE:@START='')
		{% %}
		{% fromrow {%=#SOURCE:@START%} %}
	%}
	{%?(#SOURCE:@LEN='')
		{% %}
		{% maxsize {%=#SOURCE:@LEN%} %}
	%}

	SELECT
	  TTA22_LICENCIAS_ROL.oi_licencia_rol as ID, 
	  PER16_LICENCIAS.c_licencia as COD, 
	  TTA22_LICENCIAS_ROL.d_licencia_rol as DES

	FROM					
	  TTA22_LICENCIAS_ROL,
	  PER16_LICENCIAS

	JOIN					
		TTA22_LICENCIAS_ROL.oi_licencia INNER PER16_LICENCIAS.oi_licencia

	WHERE
		1=1
		{%?(#SOURCE:@OI_FIND='') {% %} {% and ID={#SOURCE:@OI_FIND} %} %}
		{%?(#SOURCE:@TXT_FIND='') {% %} {% and (contain(ucase(DES),{upper-case(#SOURCE:@TXT_FIND)}) or contain(ucase(COD),{upper-case(#SOURCE:@TXT_FIND)})) %} %}
		{%?(#SOURCE:@WHERE='') {% %} {% and {%=#SOURCE:@WHERE%} %} %}					

	{%?(#SOURCE:@ORDERBY='')
		{% order by COD asc %}
		{% order by {%=#SOURCE:@ORDERBY%} asc %}
	%}				  

')/ROWS/ROW

for $r in SQL('
SELECT TTA22_LICENCIAS_ROL.oi_licencia_rol as ID FROM TTA22_LICENCIAS_ROL WHERE TTA22_LICENCIAS_ROL.oi_licencia = {#SOURCE:@oi_licencia}
')/ROWS/ROW
